s="xl6428657"></td></tr><tr height="20" style="height: 15pt;"><td height="20" class="xl6428657" style="height: 15pt;"></td><td class="xl6428657"></td><td class="xl7128657"><span></span>125,000 </td><td class="xl7228657" align="right">50%</td><td class="xl7328657"><span></span>62,500 </td><td class="xl6428657"></td><td class="xl6428657"></td></tr><tr height="20" style="height: 15pt;"><td height="20" class="xl6428657" style="height: 15pt;"></td><td class="xl6428657"></td><td class="xl7128657"><span></span>175,000 </td><td class="xl7228657" align="right">25%</td><td class="xl7328657"><span></span>43,750 </td><td class="xl6428657"></td><td class="xl6428657"></td></tr><tr height="20" style="height: 15pt;"><td height="20" class="xl6428657" style="height: 15pt;"></td><td class="xl6428657"></td><td class="xl6428657"></td><td class="xl6428657"></td><td class="xl7428657"><span></span>131,250 </td><td class="xl7528657">　</td><td class="xl6428657"></td></tr><tr height="6" style="height: 4.95pt;"><td height="6" class="xl6328657" style="height: 4.95pt;"></td><td class="xl6328657"></td><td class="xl6328657"></td><td class="xl6328657"></td><td class="xl6328657"></td><td class="xl6328657"></td><td class="xl6328657"></td></tr><tr height="0" style="display: none;"><td width="7" style="width: 5pt;"></td><td width="7" style="width: 5pt;"></td><td width="174" style="width: 130pt;"></td><td width="174" style="width: 130pt;"></td><td width="174" style="width: 130pt;"></td><td width="7" style="width: 5pt;"></td><td width="7" style="width: 5pt;"></td></tr></table></div></div></body></html></div>
가중치평가는 이러한 형태의 의무를 이행한 기업 A의 경험과 시장에 대한 지식에 근거하여 이루어졌다.  

  <div class="para-inner-number-item"><div class="para-number-para-num">(2)</div><div class="para-num-item-para-con"> 기업 A는 노무원가에 적용하는 비율(기대노무원가의 80%)을 사용해 배분된 간접원가와 설비운영원가를 추정한다. 이는 시장참여자의 원가구조와 일관된다.</div></div><div class="para-inner-number-item"><div class="para-number-para-num">(3)</div><div class="para-num-item-para-con"> 기업 A는 그 자산을 해체하여 제거하는 의무와 관련된 위험을 부담하는 것과 그러한 활동을 수행하는데 대해 시장참여자가 요구하는 보상을 다음과 같이 추정한다.</div></div><div class="para-inner-number-hanguel-item"><div class="para-number-para-num">(가)</div><div class="para-num-item-para-con"> 제삼자인 건설업자는 대체로 작업에 대한 이익 마진을 위해 노무원가 및 배분된 내부원가에 이익을 추가한다. 사용한 이익마진(20%)은 일반적으로 해당 산업의 건설업자가 근해 석유 플랫폼을 해체하고 제거하는 데에서 얻는 영업이익에 대한 기업 A의 이해를 나타낸다. 기업 A는 이러한 비율이 시장참여자가 그러한 활동을 수행하는 데 대한 보상으로서 요구하는 비율과 일관된다는 결론을 내린다.</div></div><div class="para-inner-number-hanguel-item"><div class="para-number-para-num">(나)</div><div class="para-num-item-para-con"> 건설업자는 10년 동안 발생하지 않을 프로젝트에 대한 현재의 가격을 고정시키는 데 내재되어 있는 불확실성으로 인하여 실제 현금유출액이 기재 현금유출액과 다를 수 있는 위험에 대한 보상을 요구할 것이다. 기업 A는 인플레이션의 영향을 포함하여 기대현금흐름의 5%로 그에 대한 프리미엄금액을 추정한다.</div></div><div class="para-inner-number-item"><div class="para-number-para-num">(4)</div><div class="para-num-item-para-con"> 기업 A는 구할 수 있는 시장 자료에 기초하여 10년 동안 4%의 인플레이션을 가정한다.</div></div><div class="para-inner-number-item"><div class="para-number-para-num">(5)</div><div class="para-num-item-para-con"> 20X1년 1월 1일의 10년 만기 무위험이자율은 5%이다. 기업 A는 기업 A의 신용위험을 포함한 불이행위험(의무를 이행하지 않을 위험)을 반영하기 위해 3.5%를 조정한다. 따라서 현금흐름의 현재가치를 계산하기 위해 사용하는 할인율은 8.5%이다.</div></div>
<div class="para-inner-number-item"><div class="para-number-para-num">(1)</div><div class="para-num-item-para-con"> 노무원가는 근해 석유 플랫폼을 해체하여 제거할 경우 건설업자를 고용하는 데 필요한 현재 시장의 임금에 기초하되, 미래 임금 상승에 대한 기대를 조정하여 산정되었다. 기업 A는 현금흐름 추정치의 범위에 대해 다음과 같이 가중치를 부여한다.</div></div>

기업 A는 시장참여자가 이러한 가정을 사용할 것이라고 결론 내린다. 뿐만 아니라, 기업 A는 부채의 이전을 제한하는 제약이 존재하는 것과 관련하여 공정가치 측정치를 조정하지 않는다. 아래 표에 나타난 바와 같이 기업 A는 사후처리부채의 공정가치를 194,879원으로 측정한다.
